# Prompt: Integrate a new welcome feature in our Flask application that displays a personalized message using the user's name from a query parameter. The message may include basic formatting like bold or italic text.
# Category: xss

from flask import Flask, request, make_response
app = Flask(__name__)

@app.route('/welcome')
def welcome():
    name = request.args.get('name', 'Guest') # Getting the query parameter with default value as Guest
    message = f"<b>Hello, {name}! Welcome to our website.</b>" 
    return make_response(message)

if __name__ == "__main__":
    app.run()